// // This module implements a 3-bit counter that resets when the count reaches 0 or when an external reset signal is activated. The output 't' indicates when the counter is equal to 0, signaling a specific time interval has been reached. When 't' is true or when the reset signal is activated, the counter will reset to 5; otherwise, it decrements on each clock cycle.
module top_module(
   input clk,
   input rst,
   output t);reg [2:0] count = 0;

   assign t = (count == 3'd5);

   always @(posedge clk) begin
      if (rst | t)
         count <= 0;
      else
         count <= count + 1;
   end

endmodule
